#!/usr/bin/env node

/**
 * School of Pipsology — "So Easy It's Ridiculous" Strategy
 * M5 Execution with H1 Trend Filtering.
 */

import fs from "fs";
import { ICMarketsClient } from "./icmarkets.js";
import { config } from "./config.js";
import { calculateIndicators } from "./indicators.js";
import { RiskManager } from "./risk-manager.js";

const STATE_FILE = "state.json";
const AUTO_EXECUTE = process.argv.includes("--auto-execute");
const PAIRS = config.tradingPairs;

const icmarkets = new ICMarketsClient();
const riskManager = new RiskManager(config);
const pairState = new Map();

function getState(pair) {
  if (!pairState.has(pair)) {
    pairState.set(pair, {
      candleCache: [],
      htfCandles: [],
      activeTrades: [],
      lastLogTime: 0,
      needsRefresh: true
    });
  }
  return pairState.get(pair);
}

async function run() {
  console.log(`\n${"═".repeat(60)}`);
  console.log(`   SCHOOL OF PIPSOLOGY — EURUSD M5 BOT`);
  console.log(`  Mode: ${AUTO_EXECUTE ? " AUTO-EXECUTE" : " MONITOR ONLY"}`);
  console.log(`${"═".repeat(60)}\n`);

  await icmarkets.connect();
  await icmarkets.authenticate();

  // Load existing state
  loadState();

  // Reconcile open positions on startup
  for (const pair of PAIRS) {
    await reconcileAccount(pair);
    await icmarkets.subscribeTicks(pair);
  }

  icmarkets.on(2126, (payload) => handleExecutionEvent(payload));

  // Ticks are handled by a standard loop to maintain regular polling
  setInterval(tick, config.pollIntervalSeconds * 1000);
}

async function tick() {
  const timestamp = new Date().toLocaleTimeString();
  const now = new Date();

  // Check trading session (8am - 12pm EST -> 12:00 - 16:00 UTC)
  const h = now.getUTCHours();
  const day = now.getUTCDay();
  if (day === 0 || day === 6 || h < config.sessionStartUTC || h >= config.sessionEndUTC) {
    process.stdout.write(`[${timestamp}]  Outside trading session (${h}:00 UTC)\r`);
    return;
  }

  for (const pair of PAIRS) {
    await tickPair(pair, timestamp).catch(err => console.error(`  ❌ ${pair} error:`, err.message));
  }
}

async function tickPair(pair, timestamp) {
  const state = getState(pair);
  const now = Date.now();

  // 1. Update Candles
  if (state.needsRefresh || state.candleCache.length < 50) {
    state.candleCache = await icmarkets.getCandles(pair, config.granularity, 200);
    state.needsRefresh = false;
  }

  // HTF Fetch every minute
  if (!state.lastHTFTime || (now - state.lastHTFTime > 60000)) {
    state.htfCandles = await icmarkets.getCandles(pair, config.htfGranularity, 200);
    state.lastHTFTime = now;
  }

  if (state.candleCache.length < 50 || state.htfCandles.length < 50) return;

  // 2. Indicators
  const ind = calculateIndicators(state.candleCache);
  const htf = calculateIndicators(state.htfCandles);

  // 3. Strategic View (H1 Trend)
  const htfTrend = htf.ema5 > htf.ema10 ? "BULLISH" : "BEARISH";

  // 4. Tactical Entry (M5)
  let action = "WAIT";

  const isBuy = ind.ema5 > ind.ema10 && ind.isStochHeadingUp && !ind.isStochOverbought && ind.rsi > 50 && htfTrend === "BULLISH";
  const isSell = ind.ema5 < ind.ema10 && ind.isStochHeadingDown && !ind.isStochOversold && ind.rsi < 50 && htfTrend === "BEARISH";

  if (isBuy) action = "BUY";
  if (isSell) action = "SELL";

  // Log status every minute
  if (now - (state.lastLogTime || 0) > 60000) {
    console.log(`[${timestamp}] ${pair} | H1: ${htfTrend} | RSI: ${ind.rsi?.toFixed(1)} | STOCH: ${ind.stochK?.toFixed(1)}/${ind.stochD?.toFixed(1)}`);
    state.lastLogTime = now;
  }

  if (action === "WAIT") return;

  // 5. Execution
  if (state.activeTrades.length >= config.maxTradesPerPair) return;

  const px = ind.currentPrice;
  const isJPY = pair.includes("JPY");
  const pipSize = isJPY ? 0.01 : 0.0001;
  const slPips = Math.max(config.minStopDistancePips, (ind.atr / pipSize) * config.strategy.atrMultiplierSL);
  const tpPips = slPips * config.risk.minRiskReward;

  const sl = action === "BUY" ? px - (slPips * pipSize) : px + (slPips * pipSize);
  const tp = action === "BUY" ? px + (tpPips * pipSize) : px - (tpPips * pipSize);

  console.log(`\n⚡ [${timestamp}] ${pair} ${action} Signal! Px: ${px} SL: ${sl.toFixed(5)} TP: ${tp.toFixed(5)}`);

  if (!AUTO_EXECUTE) return;

  try {
    const units = riskManager.calculateVolume(pair, slPips, px);
    if (units <= 0) return;

    const res = await icmarkets.openPosition(pair, action, units, sl, tp);
    if (res && res.positionId) {
       state.activeTrades.push({ id: String(res.positionId), direction: action, pair, entry: px });
       saveState();
    }
  } catch (err) {
    console.error(`  ❌ Trade failed:`, err.message);
  }
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

function handleExecutionEvent(payload) {
  if (payload.executionType === "DEAL_FILLED" || payload.executionType === 4) {
    const deal = payload.deal;
    if (deal && deal.closePositionDetail) {
       const positionId = String(deal.positionId);
       console.log(`    Position ${positionId} closed.`);
       for (const [, state] of pairState) {
         state.activeTrades = state.activeTrades.filter(t => t.id !== positionId);
       }
       saveState();
    }
  }
}

async function reconcileAccount(pair) {
  const state = getState(pair);
  try {
    const positions = await icmarkets.reconcile();
    const symbolId = icmarkets._resolveSymbolId(pair);
    state.activeTrades = positions
      .filter(p => p.tradeData && String(p.tradeData.symbolId) === String(symbolId))
      .map(p => ({ id: String(p.positionId), direction: p.tradeData.tradeSide, pair }));
    saveState();
  } catch (err) {}
}

function loadState() {
  if (fs.existsSync(STATE_FILE)) {
    try {
      const data = JSON.parse(fs.readFileSync(STATE_FILE, "utf8"));
      if (data.activeTrades) {
        // Migration/loading
      }
    } catch (err) {}
  }
}

function saveState() {
  const allTrades = [];
  for (const [, state] of pairState) allTrades.push(...state.activeTrades);
  fs.writeFileSync(STATE_FILE, JSON.stringify({ activeTrades: allTrades }, null, 2));
}

run().catch(console.error);

#!/usr/bin/env node

/**
 * 5-10-20 EMA Scalping Strategy
 * M5 Execution on EURUSD — IC Markets cTrader
 */

import fs from "fs";
import { ICMarketsClient } from "./icmarkets.js";
import { config } from "./config.js";
import { generateSignal } from "./indicators.js";
import { RiskManager } from "./risk-manager.js";

const STATE_FILE = "state.json";
const AUTO_EXECUTE = process.argv.includes("--auto-execute");
const PAIRS = config.tradingPairs;

const icmarkets = new ICMarketsClient();
const riskManager = new RiskManager(config);
const pairState = new Map();

function getState(pair) {
  if (!pairState.has(pair)) {
    pairState.set(pair, {
      candleCache: [],
      activeTrades: [],
      lastLogTime: 0,
      needsRefresh: true
    });
  }
  return pairState.get(pair);
}

async function run() {
  console.log(`\n${"═".repeat(60)}`);
  console.log(`   5-10-20 EMA SCALPING BOT — EURUSD M5`);
  console.log(`  Mode: ${AUTO_EXECUTE ? " AUTO-EXECUTE" : " MONITOR ONLY"}`);
  console.log(`${"═".repeat(60)}\n`);

  await icmarkets.connect();
  await icmarkets.authenticate();

  loadState();

  for (const pair of PAIRS) {
    await reconcileAccount(pair);
    await icmarkets.subscribeTicks(pair);
  }

  icmarkets.on(2126, (payload) => handleExecutionEvent(payload));

  setInterval(tick, config.pollIntervalSeconds * 1000);
}

async function tick() {
  const timestamp = new Date().toLocaleTimeString();
  const now = new Date();

  const h   = now.getUTCHours();
  const day = now.getUTCDay();
  if (day === 0 || day === 6 || h < config.sessionStartUTC || h >= config.sessionEndUTC) {
    process.stdout.write(`[${timestamp}]  Outside trading session (${h}:00 UTC)\r`);
    return;
  }

  for (const pair of PAIRS) {
    await tickPair(pair, timestamp).catch(err => console.error(`  ❌ ${pair} error:`, err.message));
  }
}

async function tickPair(pair, timestamp) {
  const state = getState(pair);
  const now   = Date.now();
  const isJPY = pair.includes("JPY");

  // 1. Fetch candles (rolling 100-candle window)
  if (state.needsRefresh || state.candleCache.length < 30) {
    state.candleCache = await icmarkets.getCandles(pair, config.granularity, 100);
    state.needsRefresh = false;
  }

  if (state.candleCache.length < 22) return;

  // 2. Generate signal
  const signal = generateSignal(state.candleCache, {
    pipBuffer: config.strategy.pipBuffer,
    rrRatio:   config.strategy.rrRatio,
    isJPY,
  });

  // Log status every minute
  if (now - (state.lastLogTime || 0) > 60000) {
    console.log(
      `[${timestamp}] ${pair} | Trend: ${signal.trend.toUpperCase()} | ` +
      `EMA5: ${signal.ema5} EMA10: ${signal.ema10} EMA20: ${signal.ema20} | ` +
      `Signal: ${signal.signal.toUpperCase()}`
    );
    if (signal.signal !== 'none') console.log(`  → ${signal.reason}`);
    state.lastLogTime = now;
  }

  if (signal.signal === 'none') return;

  // 3. Trade gate
  if (state.activeTrades.length >= config.maxTradesPerPair) return;

  const action = signal.signal.toUpperCase(); // 'BUY' | 'SELL'

  console.log(
    `\n⚡ [${timestamp}] ${pair} ${action} | ` +
    `Entry: ${signal.entry} SL: ${signal.sl} TP: ${signal.tp} | ` +
    `Risk: ${signal.riskPips}p Reward: ${signal.rewardPips}p`
  );

  if (!AUTO_EXECUTE) return;

  try {
    const units = riskManager.calculateVolume(pair, signal.riskPips, signal.entry);
    if (units <= 0) return;

    const res = await icmarkets.openPosition(pair, action, units, signal.sl, signal.tp);
    if (res && res.positionId) {
      state.activeTrades.push({ id: String(res.positionId), direction: action, pair, entry: signal.entry });
      saveState();
    }
  } catch (err) {
    console.error(`  ❌ Trade failed:`, err.message);
  }
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

function handleExecutionEvent(payload) {
  if (payload.executionType === "DEAL_FILLED" || payload.executionType === 4) {
    const deal = payload.deal;
    if (deal && deal.closePositionDetail) {
      const positionId = String(deal.positionId);
      console.log(`    Position ${positionId} closed.`);
      for (const [, state] of pairState) {
        state.activeTrades = state.activeTrades.filter(t => t.id !== positionId);
      }
      saveState();
    }
  }
}

async function reconcileAccount(pair) {
  const state = getState(pair);
  try {
    const positions = await icmarkets.reconcile();
    const symbolId = icmarkets._resolveSymbolId(pair);
    state.activeTrades = positions
      .filter(p => p.tradeData && String(p.tradeData.symbolId) === String(symbolId))
      .map(p => ({ id: String(p.positionId), direction: p.tradeData.tradeSide, pair }));
    saveState();
  } catch (err) {}
}

function loadState() {
  if (fs.existsSync(STATE_FILE)) {
    try {
      const data = JSON.parse(fs.readFileSync(STATE_FILE, "utf8"));
      if (data.activeTrades) {
        // Migration: flat activeTrades array — no per-pair state needed
      }
    } catch (err) {}
  }
}

function saveState() {
  const allTrades = [];
  for (const [, state] of pairState) allTrades.push(...state.activeTrades);
  fs.writeFileSync(STATE_FILE, JSON.stringify({ activeTrades: allTrades }, null, 2));
}

run().catch(console.error);

/**
 * Indicators — School of Pipsology "So Easy It's Ridiculous" Setup
 */

import { config } from "./config.js";

export function calculateIndicators(candles) {
  if (!candles || candles.length === 0) {
    console.error("  ❌ calculateIndicators: No candles provided!");
    return null;
  }
  const closes = candles.map(c => parseFloat(c.mid.c));
  const highs  = candles.map(c => parseFloat(c.mid.h));
  const lows   = candles.map(c => parseFloat(c.mid.l));

  if (closes.some(isNaN)) {
    console.error("  ❌ calculateIndicators: Some candles have NaN mid prices!");
  }

  const emaFast = config.strategy?.emaFast || 5;
  const emaSlow = config.strategy?.emaSlow || 10;
  const rsiPeriod = config.strategy?.rsiPeriod || 14;
  const stochK = config.strategy?.stochK || 10;
  const stochD = config.strategy?.stochD || 3;
  const stochS = config.strategy?.stochS || 3;

  // 1. Exponential Moving Averages
  const fastEma = calculateEMA(closes, emaFast);
  const slowEma = calculateEMA(closes, emaSlow);
  const prevFastEma = calculateEMA(closes.slice(0, -1), emaFast);
  const prevSlowEma = calculateEMA(closes.slice(0, -1), emaSlow);

  // 2. Relative Strength Index (RSI 14)
  const currentRsi = calculateRSI(closes, rsiPeriod);

  // 3. Stochastics (10, 3, 3)
  const stoch = calculateStochastic(highs, lows, closes, stochK, stochD, stochS);

  // 4. Volatility (for SL/TP guidance)
  const atrVal = calculateATR(highs, lows, closes, 14);

  return {
    currentPrice: closes[closes.length - 1],
    ema5: fastEma,
    ema10: slowEma,
    prevEma5: prevFastEma,
    prevEma10: prevSlowEma,
    rsi: currentRsi,
    stochK: stoch.k,
    stochD: stoch.d,
    prevStochK: stoch.prevK,
    prevStochD: stoch.prevD,
    atr: atrVal,

    // Cross Detection
    isBullishCross: prevFastEma <= prevSlowEma && fastEma > slowEma,
    isBearishCross: prevFastEma >= prevSlowEma && fastEma < slowEma,

    // Directional Bias
    isStochHeadingUp: stoch.k > stoch.prevK && stoch.d > stoch.prevD,
    isStochHeadingDown: stoch.k < stoch.prevK && stoch.d < stoch.prevD,
    isStochOverbought: stoch.k > 80 || stoch.d > 80,
    isStochOversold: stoch.k < 20 || stoch.d < 20,
  };
}

// ─── Helper Functions ────────────────────────────────────────────────────────

function calculateEMA(values, period) {
  if (values.length < 2) return 0;
  const actualPeriod = Math.min(period, values.length);
  const k = 2 / (actualPeriod + 1);
  let ema = values.slice(0, actualPeriod).reduce((a, b) => a + b, 0) / actualPeriod;
  for (let i = actualPeriod; i < values.length; i++) {
    ema = values[i] * k + ema * (1 - k);
  }
  return ema;
}

function calculateRSI(values, period) {
  if (values.length < 2) return 50;
  const actualPeriod = Math.min(period, values.length - 1);
  let gains = 0, losses = 0;
  for (let i = 1; i <= actualPeriod; i++) {
    const diff = values[i] - values[i - 1];
    if (diff > 0) gains += diff; else losses -= diff;
  }
  let avgGain = gains / actualPeriod, avgLoss = losses / actualPeriod;
  for (let i = actualPeriod + 1; i < values.length; i++) {
    const diff = values[i] - values[i - 1];
    avgGain = (avgGain * (actualPeriod - 1) + (diff > 0 ? diff : 0)) / actualPeriod;
    avgLoss = (avgLoss * (actualPeriod - 1) + (diff < 0 ? -diff : 0)) / actualPeriod;
  }
  return avgLoss === 0 ? 100 : 100 - 100 / (1 + avgGain / avgLoss);
}

function calculateStochastic(highs, lows, closes, kPeriod, dPeriod, sPeriod) {
  if (closes.length < kPeriod + dPeriod + sPeriod) return { k: 50, d: 50, prevK: 50, prevD: 50 };

  const calculateRawK = (h, l, c, index) => {
    const windowH = Math.max(...h.slice(index - kPeriod + 1, index + 1));
    const windowL = Math.min(...l.slice(index - kPeriod + 1, index + 1));
    return ((c[index] - windowL) / (windowH - windowL)) * 100;
  };

  const rawKs = closes.map((_, i) => i < kPeriod - 1 ? 50 : calculateRawK(highs, lows, closes, i));
  const smoothKs = rawKs.map((_, i) => i < sPeriod - 1 ? 50 : rawKs.slice(i - sPeriod + 1, i + 1).reduce((a, b) => a + b, 0) / sPeriod);
  const smoothDs = smoothKs.map((_, i) => i < dPeriod - 1 ? 50 : smoothKs.slice(i - dPeriod + 1, i + 1).reduce((a, b) => a + b, 0) / dPeriod);

  return {
    k: smoothKs[smoothKs.length - 1],
    d: smoothDs[smoothDs.length - 1],
    prevK: smoothKs[smoothKs.length - 2],
    prevD: smoothDs[smoothDs.length - 2],
  };
}

function calculateATR(highs, lows, closes, period) {
  if (closes.length < 2) return 0.0001; // Tiny floor
  let trs = [];
  for (let i = 1; i < closes.length; i++) {
    trs.push(Math.max(highs[i] - lows[i], Math.abs(highs[i] - closes[i - 1]), Math.abs(lows[i] - closes[i - 1])));
  }
  const slice = trs.slice(-period);
  return slice.reduce((a, b) => a + b, 0) / slice.length;
}

/**
 * 5-10-20 EMA Scalping Strategy
 * ---------------------------------------------------------------
 * Designed for EURUSD on 5-minute charts, IC Markets cTrader.
 *
 * Signal logic:
 *   1. Trend aligned   → EMA5 > EMA10 > EMA20 (bull) or inverse (bear)
 *   2. Pullback check  → prior candle touched EMA10 or EMA20
 *   3. Early trigger   → current close crosses back above/below EMA10
 *   4. Entry at close, SL at trigger candle low/high, TP at 1:1.5 R:R
 *
 * Candle format expected: { mid: { o, h, l, c }, time, ... }
 */

// ─── EMA Calculation ─────────────────────────────────────────────────────────

/**
 * Calculate a full EMA series for a given period.
 * @param {number[]} closes - Oldest first
 * @param {number}   period
 * @returns {number[]} EMA values aligned to closes (NaN for warm-up)
 */
export function calcEMA(closes, period) {
  const k = 2 / (period + 1);
  const result = new Array(closes.length).fill(NaN);
  const seed = closes.slice(0, period).reduce((a, b) => a + b, 0) / period;
  result[period - 1] = seed;
  for (let i = period; i < closes.length; i++) {
    result[i] = closes[i] * k + result[i - 1] * (1 - k);
  }
  return result;
}

// ─── Trend Detection ─────────────────────────────────────────────────────────

/**
 * @typedef {'bull' | 'bear' | 'neutral'} Trend
 */

/**
 * @param {number} ema5
 * @param {number} ema10
 * @param {number} ema20
 * @returns {Trend}
 */
export function detectTrend(ema5, ema10, ema20) {
  if (ema5 > ema10 && ema10 > ema20) return 'bull';
  if (ema5 < ema10 && ema10 < ema20) return 'bear';
  return 'neutral';
}

// ─── Pullback Detection ──────────────────────────────────────────────────────

/**
 * True if the previous candle's wick touched EMA10 or EMA20.
 * @param {{ low: number, high: number }} prevCandle
 * @param {number} ema10
 * @param {number} ema20
 * @param {Trend}  trend
 * @returns {boolean}
 */
export function hasPullback(prevCandle, ema10, ema20, trend) {
  const { low, high } = prevCandle;
  if (trend === 'bull') return low <= ema10 || low <= ema20;
  if (trend === 'bear') return high >= ema10 || high >= ema20;
  return false;
}

// ─── Early Trigger ───────────────────────────────────────────────────────────

/**
 * Fire on the first candle to close back through EMA10 after a pullback.
 * @param {number} prevClose
 * @param {number} currClose
 * @param {number} ema10
 * @param {Trend}  trend
 * @returns {boolean}
 */
export function hasEarlyTrigger(prevClose, currClose, ema10, trend) {
  if (trend === 'bull') return prevClose <= ema10 && currClose > ema10;
  if (trend === 'bear') return prevClose >= ema10 && currClose < ema10;
  return false;
}

// ─── Risk / Trade Parameters ─────────────────────────────────────────────────

/**
 * @param {number} entryPrice
 * @param {{ high: number, low: number }} triggerCandle
 * @param {Trend}  trend
 * @param {{ pipBuffer?: number, rrRatio?: number, isJPY?: boolean }} opts
 * @returns {{ sl: number, tp: number, riskPips: number, rewardPips: number }}
 */
export function calcTradeParams(entryPrice, triggerCandle, trend, opts = {}) {
  const pipBuffer = opts.pipBuffer ?? 0.00005;
  const rrRatio   = opts.rrRatio   ?? 1.5;
  const pipSize   = opts.isJPY ? 0.01 : 0.0001;

  const sl = trend === 'bull'
    ? triggerCandle.low  - pipBuffer
    : triggerCandle.high + pipBuffer;

  const risk   = Math.abs(entryPrice - sl);
  const reward = risk * rrRatio;
  const tp     = trend === 'bull' ? entryPrice + reward : entryPrice - reward;

  return {
    sl:         +sl.toFixed(5),
    tp:         +tp.toFixed(5),
    riskPips:   +(risk   / pipSize).toFixed(1),
    rewardPips: +(reward / pipSize).toFixed(1),
  };
}

// ─── Main Signal Generator ───────────────────────────────────────────────────

/**
 * Generate a trading signal from the latest candle data.
 *
 * Accepts candles in cTrader project format: { mid: { o, h, l, c }, time }
 * OR plain { open, high, low, close, time } objects.
 *
 * @param {Array} candles - Chronological (oldest first), min 22 recommended
 * @param {object} opts   - Passed to calcTradeParams (pipBuffer, rrRatio, isJPY)
 * @returns {{
 *   signal: 'buy'|'sell'|'none', trend: Trend,
 *   entry: number|null, sl: number|null, tp: number|null,
 *   riskPips: number|null, rewardPips: number|null,
 *   ema5: number, ema10: number, ema20: number, reason: string
 * }}
 */
export function generateSignal(candles, opts = {}) {
  const NO_SIGNAL = (reason, extras = {}) => ({
    signal: 'none', trend: 'neutral',
    entry: null, sl: null, tp: null,
    riskPips: null, rewardPips: null,
    ema5: NaN, ema10: NaN, ema20: NaN,
    ...extras, reason,
  });

  if (!candles || candles.length < 22) {
    return NO_SIGNAL('Not enough candles for EMA20 warm-up (need ≥22)');
  }

  // Support both { mid: { c, h, l } } and plain { close, high, low }
  const normalize = c => c.mid
    ? { close: parseFloat(c.mid.c), high: parseFloat(c.mid.h), low: parseFloat(c.mid.l) }
    : { close: c.close, high: c.high, low: c.low };

  const norm    = candles.map(normalize);
  const closes  = norm.map(c => c.close);

  if (closes.some(v => isNaN(v) || v === 0)) {
    return NO_SIGNAL('Invalid candle data — NaN or zero prices detected');
  }

  // 1. EMAs
  const ema5Series  = calcEMA(closes, 5);
  const ema10Series = calcEMA(closes, 10);
  const ema20Series = calcEMA(closes, 20);

  const last = candles.length - 1;
  const prev = last - 1;

  const ema5  = ema5Series[last];
  const ema10 = ema10Series[last];
  const ema20 = ema20Series[last];

  // 2. Trend alignment
  const trend     = detectTrend(ema5, ema10, ema20);
  const baseExtras = { ema5: +ema5.toFixed(5), ema10: +ema10.toFixed(5), ema20: +ema20.toFixed(5), trend };

  if (trend === 'neutral') {
    return NO_SIGNAL('Trend not aligned — EMAs in neutral / choppy state', baseExtras);
  }

  // 3. Pullback on previous candle
  const prevEma10 = ema10Series[prev];
  const prevEma20 = ema20Series[prev];
  if (!hasPullback(norm[prev], prevEma10, prevEma20, trend)) {
    return NO_SIGNAL('No pullback to EMA10/20 on previous candle', baseExtras);
  }

  // 4. Early trigger: close crosses back through EMA10
  if (!hasEarlyTrigger(closes[prev], closes[last], ema10, trend)) {
    return NO_SIGNAL('Pullback present but early trigger not yet fired', baseExtras);
  }

  // 5. Trade parameters
  const entry = closes[last];
  const { sl, tp, riskPips, rewardPips } = calcTradeParams(entry, norm[last], trend, opts);

  if (riskPips < 2) {
    return NO_SIGNAL(`Risk too small (${riskPips} pips) — skip to avoid spread erosion`, baseExtras);
  }

  return {
    signal:     trend === 'bull' ? 'buy' : 'sell',
    trend,
    entry:      +entry.toFixed(5),
    sl,
    tp,
    riskPips,
    rewardPips,
    ...baseExtras,
    reason: `${trend.toUpperCase()} — trend aligned, pullback confirmed, early trigger fired. ` +
            `Risk: ${riskPips} pips | Reward: ${rewardPips} pips (1:${opts.rrRatio ?? 1.5})`,
  };
}
